using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsPriceTimesQuantity()
    {
        var items = CreateItems(("Part", 7.50m, 4));

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(30m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var items = CreateItems(("Item", 5m, 1));
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Item", 5m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("Item", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Item", 5m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var items = CreateItems(("Item", 5m, 1));
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        var result = _service.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-none");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_SingleOrder_ReturnsSingleElement()
    {
        var items = CreateItems(("Item", 10m, 1));
        var created = _service.CreateOrder("cust-solo", items);

        var result = _service.GetOrdersByCustomer("cust-solo");

        var single = Assert.ContainsSingle(result);
        Assert.AreEqual(created.Id, single.Id);
    }

    // --- Data-driven: Total calculation ---

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_VariousItems_CalculatesCorrectTotal(
        string description, (string name, decimal price, int qty)[] items, decimal expectedTotal)
    {
        var orderItems = CreateItems(items);

        var order = _service.CreateOrder("cust-1", orderItems);

        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {description}");
    }

    public static IEnumerable<(string description, (string name, decimal price, int qty)[] items, decimal expectedTotal)>
        TotalCalculationData =>
    [
        ("Single item qty 1", [("A", 15m, 1)], 15m),
        ("Single item qty 3", [("B", 10m, 3)], 30m),
        ("Multiple items", [("C", 5m, 2), ("D", 20m, 1)], 30m),
        ("Zero-price item", [("Free", 0m, 5), ("Paid", 10m, 1)], 10m),
    ];
}

